\begin{align*}
function(subsetbone \cup subsetbtwo \cup \{indexone\}) &= function(subsetone) + function(subsetbtwo) - function(subsetbone \cap subsetbtwo) \\
function(subsetbone \cup subsetbtwo \cup \{indexone\}) &= function(subsetbone) + function(subsettwo) - function(subsetbone \cap subsetbtwo),
